   149→   */
   150→  async _detectPatternAttributes(emailData, config) {
   151→    const detectors = config.processing_config.attributes?.detectors || [];
   152→    const detectedAttributes = [];
   153→
   154→    for (const detector of detectors) {
   155→      try {
   156→        const detection = this._applyDetector(emailData, detector);
   157→        if (detection.detected) {
   158→          // Get influence role from attribute_relevance config
   159→          const influenceRole = this._getAttributeInfluenceRole(detector.attribute, config);
   160→
   161→          detectedAttributes.push({
   162→            attribute_name: detector.attribute,
   163→            attribute_value: detection.value,
   164→            detection_method: 'pattern',
   165→            detection_evidence: detection.evidence,
   166→            influence_role: influenceRole,
   167→          });
   168→
   169→          console.log(`Detected ${detector.attribute} = ${detection.value} (evidence: ${detection.evidence})`);
   170→        }
   171→      } catch (error) {
