   178→
   179→  /**
   180→   * Apply individual detector pattern to email content
   181→   */
   182→  _applyDetector(emailData, detector) {
   183→    const { field, operation, values } = detector;
   184→
   185→    // Get the field content to search
   186→    let searchContent = '';
   187→    switch (field) {
   188→    case 'body':
   189→      searchContent = emailData.body_text || '';
   190→      break;
   191→    case 'subject':
   192→      searchContent = emailData.subject || '';
   193→      break;
   194→    case 'from.address':
   195→      searchContent = emailData.from_simple?.address || '';
   196→      break;
   197→    case 'from.name':
   198→      searchContent = emailData.from_simple?.name || '';
   199→      break;
   200→    default:
   201→      console.warn(`Unknown field type for detector: ${field}`);
   202→      return { detected: false };
   203→    }
   204→
   205→    // Apply detection operation
   206→    switch (operation) {
   207→    case 'contains_any':
   208→      for (const value of values) {
   209→        if (searchContent.toLowerCase().includes(value.toLowerCase())) {
   210→          return {
   211→            detected: true,
   212→            value: true,
   213→            evidence: `Found "${value}" in ${field}`,
   214→          };
   215→        }
   216→      }
   217→      break;
   218→
   219→    case 'regex_any':
   220→      for (const pattern of values) {
   221→        const regex = new RegExp(pattern, 'i');
   222→        const match = searchContent.match(regex);
   223→        if (match) {
   224→          return {
   225→            detected: true,
   226→            value: true,
   227→            evidence: `Regex "${pattern}" matched: "${match[0]}" in ${field}`,
   228→          };
   229→        }
   230→      }
   231→      break;
