/**
 * EmailCategorizer Node: Attribute Detection
 *
 * PURPOSE
 *  Stage 4 of the EmailCategorizer pipeline. Detects and derives contextual attributes
 *  from email content and metadata that will influence category scoring in the next stage.
 *
 * PROCESSING LOGIC
 *  1. Load configuration and input email data with candidate scores from previous stage
 *  2. Apply pattern-based detectors (regex, contains_any) for attributes like has_amount, has_due_date
 *  3. Apply derivation logic for contextual attributes (self_sent, from_financial_institution)
 *  4. Create database records for detected attributes with evidence
 *  5. Pass enriched email data with detected attributes to next stage
 *
 * DATABASE OPERATIONS
 *  - Creates stage record in email.classification_stage
 *  - Inserts detected attributes into email.detected_attributes
 *  - Updates stage with feature summary
 *
 * EXPECTED INPUT
 *  Array of email objects from RuleScoringNode with:
 *  - gmail_id, subject, body_text, from_addrs, to_addrs, etc.
 *  - session_id (from previous classification session)
 *  - candidate_scores (category scores from rule matching)
 *
 * OUTPUT FORMAT
 *  Enhanced email objects with detected_attributes array:
 *  [{
 *    gmail_id: string,
 *    session_id: string,
 *    detected_attributes: [{
 *      attribute_name: string,
 *      attribute_value: string|boolean|number,
 *      detection_method: 'pattern'|'derived'|'domain_lookup',
 *      detection_evidence: string,
 *      influence_role: string (from config)
 *    }],
 *    // ... original email fields
 *  }]
 *
 * CONFIGURATION DEPENDENCIES
 *  - config.processing_config.attributes.detectors (pattern-based detection rules)
 *  - config.processing_config.attributes.derived (derivation logic descriptions)
 *  - config.domain_lookup (for institutional domain matching)
 *  - config.performance_cache (for user addresses and domain lists)
 *
 * Extends CodeNode from n8n-simulator for local testing and development.
 */

const CodeNode = require('../../../../n8n-simulator/src/nodes/CodeNode');

class AttributeDetectionNode extends CodeNode {
  constructor() {
    super('AttributeDetection');
  }

  async execute($input) {
    const inputItems = $input.all();
    console.log('Starting attribute_detection node execution');

    // Load cached configuration
    const staticData = $getWorkflowStaticData('global');
    const config = staticData.email_categorizer_config?.config;
    if (!config) {
      throw new Error('Email categorizer configuration not found in static data');
    }

    // Get attribute processing settings from configuration
    const attributeProcessing = config.processing_config?.settings?.attribute_processing || {};
    const detectSelfSent = attributeProcessing.detect_self_sent !== false; // default true
    const resolveDomains = attributeProcessing.resolve_domains !== false; // default true
    const deriveContextFlags = attributeProcessing.derive_context_flags !== false; // default true

    console.log(
      `AttributeDetection config - detect_self_sent: ${detectSelfSent}, resolve_domains: ${resolveDomains}, derive_context_flags: ${deriveContextFlags}`
    );

    const results = [];

    for (const item of inputItems) {
      const emailData = item.json;
      console.log(`Processing attributes for email ${emailData.gmail_id}`);

      try {
        // Create database stage record
        const stageId = await this._createStageRecord(emailData.session_id, 4, 'attribute_detection');

        // Detect pattern-based attributes (always enabled)
        const patternAttributes = await this._detectPatternAttributes(emailData, config);

        // Derive contextual attributes based on node configuration
        const derivedAttributes = await this._derivedAttributes(emailData, config, {
          detectSelfSent,
          resolveDomains,
          deriveContextFlags,
        });

        // Combine all detected attributes
        const allAttributes = [...patternAttributes, ...derivedAttributes];

        // Store attributes in database
        if (allAttributes.length > 0) {
          await this._storeDetectedAttributes(emailData.session_id, stageId, allAttributes);
        }

        // Update stage with detection summary
        await this._updateStageFeatures(stageId, allAttributes);

        // Add detected attributes to email data for next stage
        const enrichedEmailData = {
          ...emailData,
          detected_attributes: allAttributes,
          stage_id: stageId,
        };

        results.push({ json: enrichedEmailData });
        console.log(`Detected ${allAttributes.length} attributes for email ${emailData.gmail_id}`);
      } catch (error) {
        console.error(`Error processing attributes for email ${emailData.gmail_id}:`, error);
        // Continue with other emails but log the error
        results.push({
          json: {
            ...emailData,
            detected_attributes: [],
            attribute_detection_error: error.message,
          },
        });
      }
    }

    console.log(`Attribute detection completed for ${results.length} emails`);
    return results;
  }

  /**
   * Create classification stage record in database
   */
  async _createStageRecord(sessionId, stageOrder, stageType) {
    // Simulate database operation - in real implementation would use PostgresNode
    console.log(`Creating stage record: session_id=${sessionId}, stage=${stageOrder}, type=${stageType}`);

    // Return simulated stage ID
    const stageId = `stage_${sessionId}_${stageOrder}_${Date.now()}`;
    return stageId;
  }

  /**
   * Detect attributes using pattern-based detectors from configuration
   */
  async _detectPatternAttributes(emailData, config) {
    const detectors = config.processing_config.attributes?.detectors || [];
    const detectedAttributes = [];

    for (const detector of detectors) {
      try {
        const detection = this._applyDetector(emailData, detector);
        if (detection.detected) {
          // Get influence role from attribute_relevance config
          const influenceRole = this._getAttributeInfluenceRole(detector.attribute, config);

          detectedAttributes.push({
            attribute_name: detector.attribute,
            attribute_value: detection.value,
            detection_method: 'pattern',
            detection_evidence: detection.evidence,
            influence_role: influenceRole,
          });

          console.log(`Detected ${detector.attribute} = ${detection.value} (evidence: ${detection.evidence})`);
        }
      } catch (error) {
        console.warn(`Error applying detector for ${detector.attribute}:`, error);
      }
    }

    return detectedAttributes;
  }

  /**
   * Apply individual detector pattern to email content
   */
  _applyDetector(emailData, detector) {
    const { field, operation, values } = detector;

    // Get the field content to search
    let searchContent = '';
    switch (field) {
    case 'body':
      searchContent = emailData.body_text || '';
      break;
    case 'subject':
      searchContent = emailData.subject || '';
      break;
    case 'from.address':
      searchContent = emailData.from_simple?.address || '';
      break;
    case 'from.name':
      searchContent = emailData.from_simple?.name || '';
      break;
    default:
      console.warn(`Unknown field type for detector: ${field}`);
      return { detected: false };
    }

    // Apply detection operation
    switch (operation) {
    case 'contains_any':
      for (const value of values) {
        if (searchContent.toLowerCase().includes(value.toLowerCase())) {
          return {
            detected: true,
            value: true,
            evidence: `Found "${value}" in ${field}`,
          };
        }
      }
      break;

    case 'regex_any':
      for (const pattern of values) {
        const regex = new RegExp(pattern, 'i');
        const match = searchContent.match(regex);
        if (match) {
          return {
            detected: true,
            value: true,
            evidence: `Regex "${pattern}" matched: "${match[0]}" in ${field}`,
          };
        }
      }
      break;

    case 'starts_with':
      for (const value of values) {
        if (searchContent.toLowerCase().startsWith(value.toLowerCase())) {
          return {
            detected: true,
            value: true,
            evidence: `${field} starts with "${value}"`,
          };
        }
      }
      break;

    default:
      console.warn(`Unknown operation type: ${operation}`);
    }

    return { detected: false };
  }

  /**
   * Derive contextual attributes using logical rules
   */
  async _derivedAttributes(emailData, config, options = {}) {
    const { detectSelfSent = true, resolveDomains = true, deriveContextFlags = true } = options;
    const derivedAttributes = [];

    // Derive self_sent attribute (if enabled)
    if (detectSelfSent) {
      const selfSent = this._deriveSelfSent(emailData);
      if (selfSent.detected) {
        derivedAttributes.push(selfSent);
      }
    }

    // Domain-based derivations (if enabled)
    if (resolveDomains) {
      // Derive from_financial_institution attribute
      const financialInstitution = this._deriveFromFinancialInstitution(emailData, config);
      if (financialInstitution.detected) {
        derivedAttributes.push(financialInstitution);

        // Also derive financial_institution_type if applicable
        const institutionType = this._deriveFinancialInstitutionType(emailData, config);
        if (institutionType.detected) {
          derivedAttributes.push(institutionType);
        }
      }

      // Derive from_newsletter_source attribute
      const newsletterSource = this._deriveFromNewsletterSource(emailData, config);
      if (newsletterSource.detected) {
        derivedAttributes.push(newsletterSource);
      }

      // Derive from_logistics_carrier attribute
      const logisticsCarrier = this._deriveFromLogisticsCarrier(emailData, config);
      if (logisticsCarrier.detected) {
        derivedAttributes.push(logisticsCarrier);
      }
    }

    // Additional context flags (if enabled) - placeholder for future attributes
    if (deriveContextFlags) {
      // Could add more contextual derivations here like:
      // - email_priority from subject/content analysis
      // - sender_reputation from domain analysis
      // - content_type classification
    }

    return derivedAttributes;
  }

  /**
   * Derive self_sent attribute - email sent from user to self
   */
  _deriveSelfSent(emailData) {
    const userAddresses = this._getUserAddresses();
    const fromAddress = emailData.from_simple?.address?.toLowerCase();

    // Check if from address is user address
    if (!userAddresses.includes(fromAddress)) {
      return { detected: false };
    }

    // Check if all recipients are user addresses
    const allRecipients = [];
    if (emailData.to_addrs?.value) {
      allRecipients.push(...emailData.to_addrs.value.map((addr) => addr.address.toLowerCase()));
    }
    if (emailData.cc_addrs?.value) {
      allRecipients.push(...emailData.cc_addrs.value.map((addr) => addr.address.toLowerCase()));
    }
    if (emailData.bcc_addrs?.value) {
      allRecipients.push(...emailData.bcc_addrs.value.map((addr) => addr.address.toLowerCase()));
    }

    const allRecipientsAreUser = allRecipients.every((addr) => userAddresses.includes(addr));

    // Check for List-Id header (exclude mailing lists)
    const hasListId = emailData.headers && emailData.headers['list-id'];

    if (allRecipientsAreUser && !hasListId) {
      return {
        detected: true,
        attribute_name: 'self_sent',
        attribute_value: true,
        detection_method: 'derived',
        detection_evidence: 'All recipients match user addresses',
        influence_role: 'CORE',
      };
    }

    return { detected: false };
  }

  /**
   * Derive from_financial_institution attribute using domain lookup
   */
  _deriveFromFinancialInstitution(emailData, config) {
    const fromAddress = emailData.from_simple?.address?.toLowerCase();
    if (!fromAddress) return { detected: false };

    const fromDomain = this._extractBaseDomain(fromAddress);
    const financialDomains = config.performance_cache?.financial_domains || [];

    if (financialDomains.includes(fromDomain)) {
      return {
        detected: true,
        attribute_name: 'from_financial_institution',
        attribute_value: true,
        detection_method: 'domain_lookup',
        detection_evidence: `${fromDomain}`,
        influence_role: 'PRIMARY_BOOST',
      };
    }

    return { detected: false };
  }

  /**
   * Derive financial_institution_type from domain metadata
   */
  _deriveFinancialInstitutionType(emailData, config) {
    const fromAddress = emailData.from_simple?.address?.toLowerCase();
    if (!fromAddress) return { detected: false };

    const fromDomain = this._extractBaseDomain(fromAddress);
    const domainLookup = config.domain_lookup?.financial;

    if (domainLookup) {
      for (const confidenceLevel of ['high_confidence', 'medium_confidence', 'low_confidence']) {
        const domains = domainLookup[confidenceLevel] || [];
        const domainEntry = domains.find((d) => d.domain === fromDomain);
        if (domainEntry && domainEntry.type) {
          return {
            detected: true,
            attribute_name: 'financial_institution_type',
            attribute_value: domainEntry.type,
            detection_method: 'domain_lookup',
            detection_evidence: `${fromDomain} metadata`,
            influence_role: 'DERIVED_LINK',
          };
        }
      }
    }

    return { detected: false };
  }

  /**
   * Derive from_newsletter_source attribute
   */
  _deriveFromNewsletterSource(emailData, config) {
    const fromAddress = emailData.from_simple?.address?.toLowerCase();
    if (!fromAddress) return { detected: false };

    const fromDomain = this._extractBaseDomain(fromAddress);
    const newsletterDomains = config.performance_cache?.newsletter_domains || [];

    // Check domain match
    if (newsletterDomains.includes(fromDomain)) {
      return {
        detected: true,
        attribute_name: 'from_newsletter_source',
        attribute_value: true,
        detection_method: 'domain_lookup',
        detection_evidence: `${fromDomain}`,
        influence_role: 'PRIMARY_BOOST',
      };
    }

    // Check List-Id header presence
    const hasListId = emailData.headers && emailData.headers['list-id'];
    if (hasListId) {
      return {
        detected: true,
        attribute_name: 'from_newsletter_source',
        attribute_value: true,
        detection_method: 'derived',
        detection_evidence: 'List-Id header present',
        influence_role: 'PRIMARY_BOOST',
      };
    }

    return { detected: false };
  }

  /**
   * Derive from_logistics_carrier attribute
   */
  _deriveFromLogisticsCarrier(emailData, config) {
    const fromAddress = emailData.from_simple?.address?.toLowerCase();
    if (!fromAddress) return { detected: false };

    const fromDomain = this._extractBaseDomain(fromAddress);
    const logisticsDomains = config.performance_cache?.logistics_domains || [];

    if (logisticsDomains.includes(fromDomain)) {
      return {
        detected: true,
        attribute_name: 'from_logistics_carrier',
        attribute_value: true,
        detection_method: 'domain_lookup',
        detection_evidence: `${fromDomain}`,
        influence_role: 'PRIMARY_BOOST',
      };
    }

    return { detected: false };
  }

  /**
   * Get attribute influence role from configuration
   */
  _getAttributeInfluenceRole(attributeName, _config) {
    // This is simplified - in full implementation would check attribute_relevance config
    // for category-specific roles and return appropriate role
    const defaultRoles = {
      has_amount: 'SECONDARY_BOOST',
      has_due_date: 'SECONDARY_BOOST',
      requires_action: 'PRIMARY_BOOST',
      tracking_present: 'PRIMARY_BOOST',
      unsubscribe_present: 'SECONDARY_BOOST',
    };

    return defaultRoles[attributeName] || 'NEUTRAL';
  }

  /**
   * Extract base domain from email address
   */
  _extractBaseDomain(email) {
    const domainPart = email.split('@')[1];
    if (!domainPart) return '';

    // Handle subdomains - return main domain for common patterns
    const parts = domainPart.split('.');
    if (parts.length >= 2) {
      return parts.slice(-2).join('.');
    }
    return domainPart;
  }

  /**
   * Get user email addresses for self_sent detection
   */
  _getUserAddresses() {
    // In real implementation, this would come from user configuration
    // For now, return common patterns based on the sample data
    return [
      'scotthamilton77@gmail.com',
      // Add other user addresses from configuration
    ];
  }

  /**
   * Store detected attributes in database
   */
  async _storeDetectedAttributes(sessionId, stageId, attributes) {
    console.log(`Storing ${attributes.length} detected attributes in database`);

    // Simulate database insert for each attribute
    for (const attr of attributes) {
      console.log(`INSERT INTO email.detected_attributes: ${attr.attribute_name} = ${attr.attribute_value}`);
      // In real implementation: PostgresNode insert operation
      // INSERT INTO email.detected_attributes (session_id, stage_id, attribute_name, ...)
      // VALUES (sessionId, stageId, attr.attribute_name, ...)
    }
  }

  /**
   * Update stage record with feature extraction summary
   */
  async _updateStageFeatures(stageId, attributes) {
    const summary = {
      attributes_detected: attributes.map((a) => a.attribute_name),
      detection_summary: `Detected ${attributes.length} attributes: ${attributes
        .map((a) => `${a.attribute_name}=${a.attribute_value}`)
        .join(', ')}`,
    };

    console.log(`Updating stage ${stageId} with feature summary:`, summary);
    // In real implementation: PostgresNode update operation
  }
}

