/**
 * Test for AttributeDetectionNode
 *
 * Tests the attribute detection functionality with various email patterns
 * to ensure all detectors and derivation logic work correctly.
 */

const AttributeDetectionNode = require('../../../src/workflows/EmailCategorizer/AttributeDetectionNode');
// Initialize execution context globals
const { ExecutionContextAPI } = require('../../../../n8n-simulator/src/runtime/ExecutionContext');
const { $getWorkflowStaticData, $ } = ExecutionContextAPI; // Still imported but tests now rely on global exposure

// Mock configuration setup
function setupMockConfig() {
  const staticData = $getWorkflowStaticData('global');
  staticData.email_categorizer_config = {
    config: {
      processing_config: {
        settings: {
          attribute_processing: {
            detect_self_sent: true,
            resolve_domains: true,
            derive_context_flags: true,
          },
        },
        attributes: {
          detectors: [
            {
              attribute: 'has_amount',
              field: 'body',
              operation: 'regex_any',
              values: ['\\$\\d+', 'USD', 'amount due'],
            },
            {
              attribute: 'has_due_date',
              field: 'body',
              operation: 'contains_any',
              values: ['due by', 'due on', 'due date', 'pay by', 'payment due'],
            },
            {
              attribute: 'requires_action',
              field: 'body',
              operation: 'contains_any',
              values: ['please review', 'action required', 'needs attention'],
            },
            {
              attribute: 'tracking_present',
              field: 'body',
              operation: 'contains_any',
              values: ['tracking number', 'track your package'],
            },
            {
              attribute: 'unsubscribe_present',
              field: 'body',
              operation: 'contains_any',
              values: ['unsubscribe', 'manage preferences'],
            },
          ],
        },
      },
      domain_lookup: {
        financial: {
          high_confidence: [
            { domain: 'chase.com', type: 'bank' },
            { domain: 'bankofamerica.com', type: 'bank' },
            { domain: 'paypal.com', type: 'payment_processor' },
          ],
        },
        newsletter: {
          medium_confidence: [
            { domain: 'medium.com', type: 'publication' },
            { domain: 'substack.com', type: 'newsletter' },
          ],
        },
        logistics: {
          high_confidence: [
            { domain: 'fedex.com', type: 'carrier' },
            { domain: 'ups.com', type: 'carrier' },
          ],
        },
      },
      performance_cache: {
        financial_domains: ['chase.com', 'bankofamerica.com', 'paypal.com'],
        newsletter_domains: ['medium.com', 'substack.com'],
        logistics_domains: ['fedex.com', 'ups.com'],
      },
    },
  };
  return staticData;
}

// Test cases
const testCases = [
  {
    name: 'Financial email from bank',
    input: {
      gmail_id: 'test_financial_1',
      session_id: 'session_fin_1',
      subject: 'Your monthly statement is ready',
      body_text: 'Your statement shows a balance of $1,234.56. Payment is due by March 15th.',
      from_simple: { name: 'Chase Bank', address: 'statements@chase.com' },
      to_addrs: {
        value: [{ name: 'John Doe', address: 'john.doe@gmail.com' }],
      },
      headers: {},
    },
    expected_attributes: ['has_amount', 'has_due_date', 'from_financial_institution', 'financial_institution_type'],
  },
  {
    name: 'Self-sent reminder email',
    input: {
      gmail_id: 'test_self_1',
      session_id: 'session_self_1',
      subject: 'TODO: Call dentist',
      body_text: 'Reminder to call the dentist and schedule appointment',
      from_simple: {
        name: 'Scott Hamilton',
        address: 'scotthamilton77@gmail.com',
      },
      to_addrs: {
        value: [{ name: 'Scott Hamilton', address: 'scotthamilton77@gmail.com' }],
      },
      headers: {},
    },
    expected_attributes: ['self_sent'],
  },
  {
    name: 'Newsletter with unsubscribe',
    input: {
      gmail_id: 'test_newsletter_1',
      session_id: 'session_newsletter_1',
      subject: 'Weekly Tech Newsletter',
      body_text: 'This week\'s tech updates... Click here to unsubscribe from future emails.',
      from_simple: { name: 'Medium', address: 'noreply@medium.com' },
      to_addrs: { value: [{ name: 'Reader', address: 'reader@gmail.com' }] },
      headers: { 'list-id': '<newsletter.medium.com>' },
    },
    expected_attributes: ['unsubscribe_present', 'from_newsletter_source'],
  },
  {
    name: 'Shipping notification',
    input: {
      gmail_id: 'test_shipping_1',
      session_id: 'session_shipping_1',
      subject: 'Package shipped',
      body_text: 'Your package has shipped! Track your package with tracking number 1Z23456789.',
      from_simple: { name: 'UPS', address: 'noreply@ups.com' },
      to_addrs: {
        value: [{ name: 'Customer', address: 'customer@gmail.com' }],
      },
      headers: {},
    },
    expected_attributes: ['tracking_present', 'from_logistics_carrier'],
  },
  {
    name: 'Action required email',
    input: {
      gmail_id: 'test_action_1',
      session_id: 'session_action_1',
      subject: 'Please verify your account',
      body_text: 'Please review your recent transactions and verify your account information.',
      from_simple: { name: 'PayPal', address: 'service@paypal.com' },
      to_addrs: { value: [{ name: 'User', address: 'user@gmail.com' }] },
      headers: {},
    },
    expected_attributes: ['requires_action', 'from_financial_institution', 'financial_institution_type'],
  },
];

async function runTests() {
  console.log('Starting AttributeDetectionNode tests');
  let passedTests = 0;
  const totalTests = testCases.length;

  await ExecutionContextAPI.runWithExecutionContext(async () => {
    setupMockConfig();
    const node = new AttributeDetectionNode();

    // Mock the getWorkflowStaticData method that CodeNode expects
    node.getWorkflowStaticData = (key) => $getWorkflowStaticData(key);
    for (let i = 0; i < testCases.length; i++) {
      const testCase = testCases[i];
      console.log(`\nAI: Running test ${i + 1}/${totalTests}: ${testCase.name}`);

      try {
        const mockInput = [{ json: testCase.input }];
        const inputHelper = {
          all: () => mockInput,
          first: () => mockInput[0],
        };

        const context = { $ }; // static data accessed via execution context
        const result = await node._doRun(inputHelper, context);

        if (result && result[0] && result[0].json && result[0].json.detected_attributes) {
          const detectedAttributeNames = result[0].json.detected_attributes.map((attr) => attr.attribute_name);
          console.log(`Detected attributes: ${detectedAttributeNames.join(', ')}`);

          // Check if expected attributes were detected
          let testPassed = true;
          for (const expectedAttr of testCase.expected_attributes) {
            if (!detectedAttributeNames.includes(expectedAttr)) {
              console.log(`❌ Missing expected attribute: ${expectedAttr}`);
              testPassed = false;
            }
          }

          if (testPassed) {
            console.log(`✅ Test passed: ${testCase.name}`);
            passedTests++;
          } else {
            console.log(`❌ Test failed: ${testCase.name}`);
            console.log(`Expected: ${testCase.expected_attributes.join(', ')}`);
            console.log(`Detected: ${detectedAttributeNames.join(', ')}`);
          }
        } else {
          console.log(`❌ Test failed: ${testCase.name} - No attributes detected`);
        }
      } catch (error) {
        console.log(`❌ Test failed: ${testCase.name} - Error: ${error.message}`);
      }
    }
  });

  console.log(`\nAI: Test Results: ${passedTests}/${totalTests} tests passed`);

  if (passedTests === totalTests) {
    console.log('🎉 All tests passed!');
    return true;
  } else {
    console.log('⚠️  Some tests failed');
    return false;
  }
}

// Run tests if this file is executed directly
if (require.main === module) {
  runTests()
    .then((success) => {
      process.exit(success ? 0 : 1);
    })
    .catch((error) => {
      console.error('Test runner error:', error);
      process.exit(1);
    });
}

// Jest wrapper for the custom test runner
describe('AttributeDetectionNode', () => {
  test('should detect attributes correctly across all test cases', async () => {
    const success = await runTests();
    expect(success).toBe(true);
  });
});

module.exports = { runTests, testCases };

