     2→ * AttributeContext entity with detection metadata
     3→ *
     4→ * Cross-cutting email attributes with parallel detection capabilities,
     5→ * supporting attribute relevance matrix roles per SCORING_LOGIC.md.
     6→ */
     7→
     8→export interface AttributeContext {
     9→  emailId: string;
