import js from '@eslint/js';
import globals from 'globals';
import reactHooks from 'eslint-plugin-react-hooks';
import reactRefresh from 'eslint-plugin-react-refresh';
import { defineConfig, globalIgnores } from 'eslint/config';

export default defineConfig([
  globalIgnores(['dist']),
  {
    files: ['**/*.{js,jsx}'],
    extends: [js.configs.recommended, reactHooks.configs['recommended-latest'], reactRefresh.configs.vite],
    languageOptions: {
      ecmaVersion: 2020,
      globals: globals.browser,
      parserOptions: {
        ecmaVersion: 'latest',
        ecmaFeatures: { jsx: true },
        sourceType: 'module',
      },
    },
    rules: {
      'no-unused-vars': ['error', { varsIgnorePattern: '^[A-Z_]' }],
    },
  },
]);

module.exports = {
  extends: ['../../eslint.config.js'],
  rules: {
    // Error Handling Standards Enforcement

    // Prevent catch-and-throw-something-else patterns
    'no-throw-literal': 'error',

    // Warn about potentially problematic error handling patterns
    'prefer-promise-reject-errors': 'error',
  },

  overrides: [
    {
      // Special rules for node classes
      files: ['src/nodes/**/*.js'],
      rules: {
        // Custom rule to prevent BaseNode bypass patterns
        // This will be enforced through code review until custom eslint rule is created
        // TODO: Create custom eslint rule to detect 'async run(' methods in node classes
      },
    },
  ],
};

// Code Review Guidelines (enforced manually until custom rules available):
//
// 1. PREVENT: Custom run() methods in node classes
//    - All nodes must extend BaseNode and implement _doRun(), not run()
//    - Pattern to flag: 'async run($input)' in src/nodes/*.js files
//
// 2. PREVENT: Catch-and-throw-something-else patterns
//    - Pattern to flag: 'throw new Error(' + 'error.message'
//    - Should preserve original error object instead
//
// 3. PREVENT: Unjustified silent catches
//    - Pattern to flag: catch blocks without throw/return that lack justification comment
//    - All silent catches should have comment explaining why suppression is appropriate
//
// 4. REQUIRE: Structured error data preservation
//    - When converting output to errors, check if errorData instanceof Error first
//    - Attach original data to error object rather than converting to string

